+    var queue = lockfree.Queue(256).init();
+
+    var tasks: [256]Task = undefined;
+    for (&tasks, 0..) |*task, i| {
+        task.* = Task.init(i, undefined, undefined);
+    }
+
+    // Mixed operations
+    const start = std.time.nanoTimestamp();
+    for (0..iterations) |i| {
