+        // Buffer still full - decide whether to spin or yield
+        if (spin_count < max_spins) {
+            spin_count += 1;
+            std.atomic.spinLoopHint();
+            continue;
+        }
+
+        // Add to send queue and yield
+        {
+            chan.mutex.lock();
+            defer chan.mutex.unlock();
