+/// Poll result (Tokio-style)
+pub fn Poll(comptime T: type) type {
+    return union(enum) {
+        pending: void,
+        ready: T,
+
+        pub fn isReady(self: @This()) bool {
+            return switch (self) {
+                .ready => true,
+                .pending => false,
+            };
+        }
+
+        pub fn isPending(self: @This()) bool {
+            return switch (self) {
+                .ready => false,
+                .pending => true,
+            };
+        }
+
+        pub fn unwrap(self: @This()) T {
+            return switch (self) {
+                .ready => |value| value,
+                .pending => @panic("Poll.unwrap() called on pending future"),
+            };
+        }
+    };
