+/// Join two futures (wait for both)
+pub fn join(
+    comptime A: type,
+    comptime B: type,
+    f1: *Future(A),
+    f2: *Future(B),
+    allocator: std.mem.Allocator,
+    current_task: *Task,
+) !struct { A, B } {
+    _ = allocator;
+
+    var waker = Waker.init(current_task);
+    const ctx = Context.init(&waker);
+
+    var result1: ?A = null;
+    var result2: ?B = null;
