+            if (!completed[i]) {
+                const poll_result = future.poll(&ctx);
+                if (poll_result.isReady()) {
+                    results[i] = poll_result.unwrap();
+                    completed[i] = true;
+                } else {
+                    all_complete = false;
+                }
+            }
+        }
+
+        if (!all_complete) {
+            poll_mod.yieldNow(current_task);
+        }
+    }
