+
+    // Create tasks
+    var task1 = Task.init(1, undefined, undefined);
+    var task2 = Task.init(2, undefined, undefined);
+    var task3 = Task.init(3, undefined, undefined);
+
+    // Test empty
+    try testing.expect(queue.isEmpty());
