+    try testing.expect(stats.total_pushed == 3);
+    try testing.expect(stats.current_size == 3);
+
+    // Test pop
+    const t1 = queue.pop();
+    try testing.expect(t1 != null);
+    try testing.expect(t1.?.id == 1);
+
+    const t2 = queue.pop();
+    try testing.expect(t2 != null);
