+    try testing.expect(queue.size() == 2);
+
+    // Pop remaining
+    const t4 = queue.pop();
+    try testing.expect(t4 != null);
+    try testing.expect(t4.?.id == 3);
+
+    const t5 = queue.pop();
+    try testing.expect(t5 != null);
+    try testing.expect(t5.?.id == 4);
