+
+test "TaskArena allocation" {
+    const allocator = testing.allocator;
+
+    var task_data: u8 = 0;
+    var task = Task.init(1, testTaskFunc, &task_data);
+    var arena = TaskArena.init(allocator, &task);
+    defer arena.deinit();
+
+    // Allocate some memory
