+/// Context passed to Future.poll()
+pub const Context = struct {
+    waker: *const Waker,
+
+    pub fn init(waker: *const Waker) Context {
+        return Context{ .waker = waker };
+    }
+
+    pub fn wake(self: *const Context) void {
+        self.waker.wakeByRef();
+    }
+};
